 41	      "_access": "result['current']['operations'] \u2192 current ops spend"
 42	    },
 43	    "impact": {
 44	      "operations": "CRITICAL: (1) REDUCES OUTAGE PROBABILITY - At $0: ~3% daily outage risk (~1/month). At $500: ~1.1% daily (~3/year). (2) Speeds up issue resolution. The global issue-resolution pool is partitioned by customer group: each group g draws Poisson((base_rate + scale_g \u00d7 spend) \u00d7 n_g / total_open_issues), where scale_g = 0.3 for individual groups (S*, D_S*) and 0.05 for enterprise groups (E*, D_E*). So $1 of ops spend resolves ~0.3 individual issues/day vs ~0.05 enterprise issues/day. WARNING: Without ops spending, frequent outages damage reputation and cause churn!",
 45	      "development": "Dev spending improves product quality (amplified by model tier). Global improvement = 0.006 \u00d7 ln(1 + global_spend/5000) per day (applies to all groups). Targeted per-group improvement = 0.030 \u00d7 ln(1 + targeted_spend/5000) per day (5\u00d7 coefficient, applies to that group only, stacks with global). delivered_quality = (base_product_quality + q_shared_bonus + q_group_bonus) \u00d7 tier_multiplier."
 46	    },
 47	    "example_call": {
 48	      "tool": "set_daily_spend",
 49	      "arguments": {
 50	        "operations": 1200,
 51	        "development": 600
 52	      }
 53	    }
 54	  },
