cat > week6_actions.py <<'PY'
import novamind_api as nm
from pprint import pprint
results = {}
# Enterprise counter: do not accept unprofitable $10.41 C; offer low-cost viable alternatives and a C price near estimated WTP.
try:
    results['enterprise_deal_2945'] = nm.enterprise.send_enterprise_deal(
        deals=[[2945, [["A", 29.0], ["B", 59.0], ["C", 99.0]]]]
    )
except Exception as e:
    results['enterprise_deal_2945_error'] = str(e)

# Preserve proven S2 pricing/model fit while addressing usage-limit and support sentiment.
try:
    results['prices'] = nm.pricing.set_prices(A=39.0, B=99.0, C=149.0)
except Exception as e:
    results['prices_error'] = str(e)
try:
    results['tiers'] = nm.pricing.set_model_tiers(A=1, B=4, C=5)
except Exception as e:
    results['tiers_error'] = str(e)
try:
    results['quotas'] = nm.pricing.set_usage_quotas(A=2500, B=25000, C=100000)
except Exception as e:
    results['quotas_error'] = str(e)
try:
    results['promos'] = nm.pricing.set_promotion(global_promotion=0.0, by_group={}, by_customer={}, by_group_plan={})
except Exception as e:
    results['promos_error'] = str(e)
try:
    results['lead_promos'] = nm.marketing.set_lead_promotion(global_promotion=0.0, by_group={"S1":0.0,"S2":0.0,"S3":0.0,"D_E09":0.0})
except Exception as e:
    results['lead_promos_error'] = str(e)
try:
    results['ads_strength'] = nm.marketing.set_ads_strength(global_strength=0.0, by_group={})
except Exception as e:
    results['ads_strength_error'] = str(e)

# Scale capacity and S2 growth. Search remains a small measurement channel; content/social/referral carry the budget.
try:
    results['capacity'] = nm.infrastructure.set_capacity_tier(tier=3)
except Exception as e:
    results['capacity_error'] = str(e)
try:
    results['daily_spend'] = nm.marketing.set_daily_spend(operations=10000.0, development=1000.0)
except Exception as e:
    results['daily_spend_error'] = str(e)
try:
    results['targeted_ops'] = nm.analytics.set_targeted_ops_spend(targeted_spend={"S2": 5000.0})
except Exception as e:
    results['targeted_ops_error'] = str(e)
try:
    results['targeted_dev'] = nm.analytics.set_targeted_dev_spend(targeted_spend={"S2": 5000.0})
except Exception as e:
    results['targeted_dev_error'] = str(e)
try:
    results['targeted_ads'] = nm.marketing.set_targeted_ad_spend(targeted_spend={
        "content_marketing": {"S2": 25000.0},
        "social_media": {"S2": 7500.0},
        "referral_program": {"S2": 3000.0},
        "search_ads": {"S2": 1000.0},
        "linkedin": {}
    })
except Exception as e:
    results['targeted_ads_error'] = str(e)

# Weekly social post (<=280 chars), aligned with the quota/support changes.
try:
    results['social_post'] = nm.marketing.post_social_media(
        content="Heavy daily workflows should not feel episodic. Pro now has 25k daily units, Premium 100k, and we are expanding S2 support and publishing clearer capacity-planning guidance for 40-50 query/day teams."
    )
except Exception as e:
    results['social_post_error'] = str(e)

pprint(results)
